import{_ as i,o as t,c as a,ag as r}from"./chunks/framework.CvgP6Fyv.js";const g=JSON.parse('{"title":"Expenses","description":"","frontmatter":{},"headers":[],"relativePath":"features/expenses.md","filePath":"features/expenses.md"}'),n={name:"features/expenses.md"};function s(o,e,l,c,p,u){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="expenses" tabindex="-1">Expenses <a class="header-anchor" href="#expenses" aria-label="Permalink to &quot;Expenses&quot;">​</a></h1><p>Track all your business expenses, scan receipts with AI, and categorize costs for accurate bookkeeping and VAT filing.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The expenses page lists all your recorded expenses. Filter by:</p><ul><li><strong>Category</strong> — Office, travel, equipment, etc.</li><li><strong>Project</strong> — Expenses linked to specific projects</li><li><strong>Date range</strong> — Filter by expense date</li><li><strong>Status</strong> — Active or archived</li></ul><h2 id="creating-an-expense" tabindex="-1">Creating an expense <a class="header-anchor" href="#creating-an-expense" aria-label="Permalink to &quot;Creating an expense&quot;">​</a></h2><h3 id="manual-entry" tabindex="-1">Manual entry <a class="header-anchor" href="#manual-entry" aria-label="Permalink to &quot;Manual entry&quot;">​</a></h3><ol><li>Go to <strong>Expenses &gt; New Expense</strong></li><li>Fill in: <ul><li><strong>Description</strong> — What the expense is for</li><li><strong>Amount</strong> — Total cost (including or excluding VAT)</li><li><strong>Date</strong> — When the expense occurred</li><li><strong>Category</strong> — Select from predefined categories</li><li><strong>VAT rate</strong> — Applicable VAT percentage</li></ul></li><li>Optionally attach a <strong>receipt</strong> image or PDF</li><li>Optionally link to a <strong>project</strong> or <strong>customer</strong></li><li>Click <strong>Save</strong></li></ol><h3 id="quick-add" tabindex="-1">Quick Add <a class="header-anchor" href="#quick-add" aria-label="Permalink to &quot;Quick Add&quot;">​</a></h3><p>Use the quick-add drawer for rapid expense entry:</p><ol><li>Click the quick-add button on the expenses list</li><li>Enter the amount and description</li><li>Select a quick category</li><li>Save</li></ol><h3 id="receipt-scanning" tabindex="-1">Receipt scanning <a class="header-anchor" href="#receipt-scanning" aria-label="Permalink to &quot;Receipt scanning&quot;">​</a></h3><p>Let AI extract expense details from receipts automatically:</p><ol><li>Go to <strong>Expenses &gt; Scan Receipt</strong></li><li>Upload a receipt image (JPEG, PNG, WebP) or PDF</li><li>Choose extraction mode: <ul><li><strong>Single</strong> — One expense from the receipt</li><li><strong>Multiple</strong> — Multiple line items from one receipt</li></ul></li><li>Review the extracted data (date, amount, supplier, description)</li><li>Confirm to create the expense(s)</li></ol><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Receipt scanning requires the <strong>Pro</strong> plan or higher.</p></div><h2 id="expense-categories" tabindex="-1">Expense categories <a class="header-anchor" href="#expense-categories" aria-label="Permalink to &quot;Expense categories&quot;">​</a></h2><p>MyCompanyDesk provides predefined categories with icons for quick selection:</p><ul><li>Office supplies</li><li>Travel &amp; transport</li><li>Food &amp; drinks</li><li>Software &amp; subscriptions</li><li>Equipment</li><li>Professional services</li><li>Marketing &amp; advertising</li><li>Insurance</li><li>Rent &amp; utilities</li><li>And more...</li></ul><p>Categories help organize your expenses and are used in reports for cost breakdowns.</p><h2 id="vat-handling" tabindex="-1">VAT handling <a class="header-anchor" href="#vat-handling" aria-label="Permalink to &quot;VAT handling&quot;">​</a></h2><p>Each expense can have its own VAT rate. Common options:</p><ul><li><strong>21%</strong> — Standard rate</li><li><strong>9%</strong> — Reduced rate</li><li><strong>0%</strong> — Zero-rated or exempt</li></ul><p>The VAT amount is calculated automatically and included in your <a href="/features/vat">VAT reports</a>.</p><h2 id="linking-expenses" tabindex="-1">Linking expenses <a class="header-anchor" href="#linking-expenses" aria-label="Permalink to &quot;Linking expenses&quot;">​</a></h2><p>Link expenses to:</p><ul><li><strong>Projects</strong> — Track project costs accurately</li><li><strong>Customers</strong> — Associate costs with specific clients</li><li><strong>Suppliers</strong> — Record who you paid</li></ul><h2 id="bulk-actions" tabindex="-1">Bulk actions <a class="header-anchor" href="#bulk-actions" aria-label="Permalink to &quot;Bulk actions&quot;">​</a></h2><p>Select multiple expenses for:</p><ul><li><strong>Categorize</strong> — Change category in bulk</li><li><strong>Archive</strong> — Move to archive</li><li><strong>Delete</strong> — Permanently remove</li><li><strong>Export</strong> — Download as CSV</li></ul><h2 id="recurring-expenses" tabindex="-1">Recurring expenses <a class="header-anchor" href="#recurring-expenses" aria-label="Permalink to &quot;Recurring expenses&quot;">​</a></h2><p>For regular costs (rent, subscriptions, etc.), set up <a href="/features/recurring-expenses">recurring expenses</a> to automate creation.</p><h2 id="import" tabindex="-1">Import <a class="header-anchor" href="#import" aria-label="Permalink to &quot;Import&quot;">​</a></h2><p>Import expenses from CSV:</p><ol><li>Go to <strong>Profile &gt; Import</strong></li><li>Select <strong>Expenses</strong> as the data type</li><li>Upload your CSV file</li><li>Map columns to fields</li><li>Review and confirm</li></ol><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Enable <a href="/advanced/ai-features">AI suggestions</a> for automatic category recommendations</li><li>Always attach receipts — they&#39;re essential for tax audits</li><li>Use projects to track expense-to-revenue ratios</li><li>Check the <a href="/features/reports">expense report</a> for spending breakdowns</li></ul>',36)])])}const h=i(n,[["render",s]]);export{g as __pageData,h as default};
